using UnityEngine;

public class ColliderExample : MonoBehaviour
{
    // Collision events
    void OnCollisionEnter2D(Collision2D collision)
    {
        Debug.Log("Collision entered with: " + collision.gameObject.name);

        // Get the collider that was hit
        Collider2D collider = collision.collider;

        // Get the contact point
        ContactPoint2D contact = collision.contacts[0];
        Vector3 contactPoint = contact.point;

        // Check tag
        if (collision.gameObject.CompareTag("Player"))
        {
            Debug.Log("Hit the player!");
        }

        // Get component
        HealthComponent health = collision.gameObject.GetComponent<HealthComponent>();
        if (health != null)
        {
            health.TakeDamage(10);
        }
    }

    void OnCollisionStay2D(Collision2D collision)
    {
        // Called every frame while colliding
        // Debug.Log("Still colliding with: " + collision.gameObject.name);
    }

    void OnCollisionExit2D(Collision2D collision)
    {
        Debug.Log("Collision exited with: " + collision.gameObject.name);
    }

    // Trigger events (no physics response)
    void OnTriggerEnter2D(Collider2D other)
    {
        Debug.Log("Trigger entered with: " + other.gameObject.name);

        if (other.CompareTag("Coin"))
        {
            Debug.Log("Collected a coin!");
            Destroy(other.gameObject);
        }
    }

    void OnTriggerStay2D(Collider2D other)
    {
        // Called every frame while overlapping
    }

    void OnTriggerExit2D(Collider2D other)
    {
        Debug.Log("Trigger exited with: " + other.gameObject.name);
    }
}

// Example: Collectible item
public class Coin : MonoBehaviour
{
    public int value = 10;

    void Start()
    {
        // Ensure the coin has a trigger collider
        Collider2D collider = GetComponent<Collider2D>();
        if (collider != null)
        {
            collider.isTrigger = true;
        }
    }
}

// Example: Damage zone
public class DamageZone : MonoBehaviour
{
    public int damagePerSecond = 10;

    void OnTriggerStay2D(Collider2D other)
    {
        HealthComponent health = other.GetComponent<HealthComponent>();
        if (health != null)
        {
            health.TakeDamage(damagePerSecond);
            Debug.Log("Taking damage from zone!");
        }
    }
}

